//-----------------------------------------------------------------------------
CATBaseUnknown_var TCAEUTLGo::getInputMember(const int& i_rIdx)
{
  CATBaseUnknown_var spInputMember = NULL_var;
  if( i_rIdx < 1 )
  {
    return NULL_var;
  }

  int cnt = m_InputMembers.Size();
  while( cnt < i_rIdx )
  {
    CATBaseUnknown_var spInputMemberNew = TCAUTLInst("UTLDoItMember");
    if( !!spInputMemberNew )
    {
      m_InputMembers.Append(spInputMemberNew);
      cnt = m_InputMembers.Size();
    }
    else
    {
      break;
    }
  }

  if( cnt >= i_rIdx )
  {
    spInputMember = m_InputMembers[i_rIdx];
  }

  return spInputMember;
} // getInputMember

