//-----------------------------------------------------------------------------
// getMembers
//-----------------------------------------------------------------------------
HRESULT TCAEUTLGo::getMembers(CATListValCATBaseUnknown_var& o_rListValue)
{
  HRESULT hr = E_FAIL;
  o_rListValue.RemoveAll();
  for( int m = 1; m <= m_Members.Size(); m++ )
  {
    TCAIUTLDoItMember_var spMember = m_Members[m];
    if( !!spMember )
    {
      TCAIUTLDoItMember_var spMemberNew = TCAUTLInst("UTLDoItMember");
      if( !!spMemberNew )
      {
        o_rListValue.Append(spMemberNew);

        // name
        CATUnicodeString name;
        spMember->getName(name);
        spMemberNew->setName(name);

        // copy all values
        hr = spMemberNew->copyValuesFrom(spMember);
      }
    }
  }
  return S_OK;
} // getMembers

